import sys


def read_nums():
    return list(map(int, sys.stdin.readline().split()))


def main():
    n, f = read_nums()
    sold = 0
    days = []
    for i in range(n):
        k, l = read_nums()
        days.append(k)
        sold += k
    days.sort(reverse=True)
    for i in range(f):
        sold += days[i] * 2
    print(sold)


if __name__ == '__main__':
    main()
